package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testIsLineBreak_Character_null() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Object) null);
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_Character_withLineBreakChars() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);

        assertTrue((Boolean) method.invoke(null, (Object) '\r'));
        assertTrue((Boolean) method.invoke(null, (Object) '\n'));
    }

    @Test
    void testIsLineBreak_Character_withNonLineBreakChar() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);

        assertFalse((Boolean) method.invoke(null, (Object) 'a'));
        assertFalse((Boolean) method.invoke(null, (Object) ' '));
        assertFalse((Boolean) method.invoke(null, (Object) '\t'));
    }

    @Test
    void testIsLineBreak_char_withLineBreakChars() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);

        assertTrue((Boolean) method.invoke(null, '\r'));
        assertTrue((Boolean) method.invoke(null, '\n'));
    }

    @Test
    void testIsLineBreak_char_withNonLineBreakChar() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);

        assertFalse((Boolean) method.invoke(null, 'a'));
        assertFalse((Boolean) method.invoke(null, ' '));
        assertFalse((Boolean) method.invoke(null, '\t'));
    }
}
